import { useState } from 'react'

interface LoginProps {
  onLogin: (name: string) => void
  savedName: string | null
}

export default function Login({ onLogin, savedName }: LoginProps) {
  const [name, setName] = useState(savedName || '')

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const trimmed = name.trim()
    if (!trimmed) {
      alert('请输入姓名')
      return
    }
    onLogin(trimmed)
  }

  return (
    <div id="loginView" className="bg-white rounded-2xl p-8 shadow-lg max-w-md mx-auto">
      <h2 className="text-2xl font-bold mb-2 text-center">👋 加入协作空间</h2>
      <p className="text-gray-500 mb-6 text-center">请输入您的姓名</p>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          placeholder="填写你的名字"
          className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl text-lg focus:border-blue-500 focus:outline-none mb-4"
          autoFocus
        />
        <button
          type="submit"
          className="w-full bg-blue-500 hover:bg-blue-600 text-white font-semibold py-3 px-6 rounded-xl transition-colors"
        >
          进入工作区
        </button>
      </form>
      {savedName && (
        <p className="text-gray-400 text-sm mt-4 text-center">上次登录：{savedName}</p>
      )}
    </div>
  )
}
