import { useState, useEffect } from 'react'
import type { Member } from '@/types'
import { loadMembers, updateMemberStatus } from '@/lib/api'

interface MemberTableProps {
  currentUser: string
}

export default function MemberTable({ currentUser }: MemberTableProps) {
  const [members, setMembers] = useState<Member[]>([])
  const [myStatus, setMyStatus] = useState('')
  const [isEditing, setIsEditing] = useState(false)
  const [initialized, setInitialized] = useState(false)

  const fetchMembers = async () => {
    const data = await loadMembers()
    setMembers(data)
    const me = data.find(m => m.name === currentUser)
    if (me) {
      setMyStatus(me.status)
      await updateMemberStatus(currentUser, me.status)
    } else if (!initialized) {
      await updateMemberStatus(currentUser, '')
      setInitialized(true)
      await fetchMembers()
    }
  }

  useEffect(() => {
    fetchMembers()
    const interval = setInterval(fetchMembers, 60000)
    return () => clearInterval(interval)
  }, [currentUser])

  const handleUpdateStatus = async () => {
    const success = await updateMemberStatus(currentUser, myStatus.trim())
    if (success) {
      setIsEditing(false)
      await fetchMembers()
    } else {
      alert('保存失败')
    }
  }

  return (
    <div className="card">
      <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
        团队成员状态
        <span className="text-sm font-normal text-gray-500 ml-auto">
          当前用户：<span className="text-blue-500 font-semibold">{currentUser}</span>
        </span>
      </h2>
      
      <table className="w-full mb-4">
        <thead>
          <tr>
            <th className="text-left py-2 px-3 text-sm font-semibold text-gray-600">成员</th>
            <th className="text-left py-2 px-3 text-sm font-semibold text-gray-600">当前工作</th>
            <th className="text-left py-2 px-3 text-sm font-semibold text-gray-600">在线状态</th>
          </tr>
        </thead>
        <tbody>
          {members.length === 0 ? (
            <tr>
              <td colSpan={3} className="text-center text-gray-400 py-4">暂无成员数据</td>
            </tr>
          ) : (
            members.map((member) => (
              <tr key={member.name} className="border-b border-gray-100">
                <td className={`py-3 px-3 ${member.name === currentUser ? 'font-semibold text-blue-600' : ''}`}>
                  {member.name} {member.name === currentUser && '(我)'}
                </td>
                <td className="py-3 px-3">
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-sm bg-blue-50 text-blue-600">
                    {member.status || '暂无工作在进行'}
                  </span>
                </td>
                <td className="py-3 px-3">
                  <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-sm ${
                    member.isOnline 
                      ? 'bg-green-50 text-green-600' 
                      : 'bg-gray-50 text-gray-500'
                  }`}>
                    <span className={`w-2 h-2 rounded-full ${member.isOnline ? 'bg-green-500' : 'bg-gray-400'}`}></span>
                    {member.isOnline ? '在线' : '离线'}
                  </span>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      <div className="update-status flex flex-wrap gap-3 items-center">
        {isEditing ? (
          <>
            <input
              type="text"
              value={myStatus}
              onChange={(e) => setMyStatus(e.target.value)}
              placeholder="更新我在做什么..."
              className="flex-1 min-w-[200px] px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-blue-500"
              autoFocus
            />
            <button
              onClick={handleUpdateStatus}
              className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
            >
              保存
            </button>
            <button
              onClick={() => {
                setIsEditing(false)
                const me = members.find(m => m.name === currentUser)
                if (me) setMyStatus(me.status)
              }}
              className="px-4 py-2 border border-gray-300 text-gray-600 rounded-lg hover:bg-gray-50"
            >
              取消
            </button>
          </>
        ) : (
          <>
            <span className="text-gray-600">我的工作：</span>
            <span className="font-medium">{myStatus || '尚无正在进行的工作'}</span>
            <button
              onClick={() => setIsEditing(true)}
              className="px-4 py-2 border border-gray-300 text-gray-600 rounded-lg hover:bg-gray-50"
            >
              编辑
            </button>
          </>
        )}
      </div>
    </div>
  )
}
